import requests
import json

graphql_url = "http://127.0.0.1:8080/graphql"

print("Getting full GraphQL schema to analyze...")

introspection_query = {
    "query": """
    query IntrospectionQuery {
      __schema {
        queryType { name }
        mutationType { name }
        subscriptionType { name }
        types {
          kind
          name
          description
          fields(includeDeprecated: true) {
            name
            description
          }
        }
      }
    }
    """
}

try:
    response = requests.post(graphql_url, json=introspection_query, timeout=30)
    if response.status_code == 200:
        data = response.json()
        if "data" in data:
            schema = data["data"]["__schema"]
            print(f"Query type: {schema['queryType']['name']}")
            print(f"Mutation type: {schema['mutationType']['name']}")
            print(f"Subscription type: {schema['subscriptionType']['name']}")

            types = schema["types"]

            query_root = None
            for t in types:
                if t["name"] == schema["queryType"]["name"]:
                    query_root = t
                    break

            if query_root and "fields" in query_root:
                print(f"\nAvailable queries ({len(query_root['fields'])}):")
                interesting_queries = []
                for field in query_root["fields"]:
                    field_name = field["name"].lower()
                    if any(keyword in field_name for keyword in ["flag", "ctf", "challenge", "secret", "key", "password", "token", "auth"]):
                        interesting_queries.append(field)

                if interesting_queries:
                    print(f"\nFound {len(interesting_queries)} potentially interesting queries:")
                    for field in interesting_queries:
                        print(f"  - {field['name']}: {field.get('description', 'No description')}")
                else:
                    print("No obviously interesting queries found. Showing first 20 queries:")
                    for i, field in enumerate(query_root["fields"][:20]):
                        print(f"  - {field['name']}: {field.get('description', 'No description')}")

            print(f"\nSearching for types containing 'flag':")
            flag_types = []
            for t in types:
                if "flag" in t["name"].lower():
                    flag_types.append(t)

            if flag_types:
                print(f"Found {len(flag_types)} types with 'flag' in name:")
                for t in flag_types[:10]:  # Limit output
                    print(f"  - {t['name']}: {t.get('description', 'No description')}")
            else:
                print("No types found with 'flag' in name")

            print(f"\nSearching for mutation types:")
            mutation_types = []
            for t in types:
                if t["name"] == schema["mutationType"]["name"]:
                    mutation_types.append(t)
                    break

            if mutation_types:
                mutation_type = mutation_types[0]
                if "fields" in mutation_type:
                    print(f"Available mutations ({len(mutation_type['fields'])}):")
                    interesting_mutations = []
                    for field in mutation_type["fields"]:
                        field_name = field["name"].lower()
                        if any(keyword in field_name for keyword in ["create", "update", "delete", "add", "remove", "reset"]):
                            interesting_mutations.append(field)

                    if interesting_mutations:
                        print(f"Found {len(interesting_mutations)} potentially interesting mutations:")
                        for field in interesting_mutations[:10]:  # Limit output
                            print(f"  - {field['name']}: {field.get('description', 'No description')}")

        else:
            print("No data in response")
    else:
        print(f"Status code: {response.status_code}")
except Exception as e:
    print(f"Error: {e}")

